# gate_evidence_validator.py — validate completeness of AI gate evidence packages

from dataclasses import dataclass
from typing import List, Optional

@dataclass
class GateEvidenceRequirement:
    section: str
    required_fields: List[str]
    description: str
    is_blocking: bool = True  # if True, missing = gate cannot proceed

@dataclass
class GateEvidencePackage:
    initiative_name: str
    gate_name: str
    submitted_data: dict  # section -> field -> value

FEASIBILITY_GATE_REQUIREMENTS = [
    GateEvidenceRequirement(
        "model_performance",
        ["test_set_accuracy", "target_accuracy", "test_set_size", "test_set_description"],
        "Proof of concept accuracy on representative test set",
        is_blocking=True
    ),
    GateEvidenceRequirement(
        "data_assessment",
        ["training_data_size", "data_quality_score", "coverage_assessment"],
        "Assessment of training data quality and coverage",
        is_blocking=True
    ),
    GateEvidenceRequirement(
        "business_case",
        ["projected_annual_benefit", "implementation_cost", "payback_period_months"],
        "Validated business case with data-based projections",
        is_blocking=True
    ),
    GateEvidenceRequirement(
        "risks",
        ["top_3_risks", "mitigation_plans"],
        "Top 3 risks with mitigation plans",
        is_blocking=False
    ),
]

def validate_evidence_package(
    package: GateEvidencePackage,
    requirements: List[GateEvidenceRequirement]
) -> dict:
    missing_blocking = []
    missing_non_blocking = []

    for req in requirements:
        section_data = package.submitted_data.get(req.section, {})
        missing = [f for f in req.required_fields if f not in section_data or not section_data[f]]
        if missing:
            if req.is_blocking:
                missing_blocking.extend([f"{req.section}.{f}" for f in missing])
            else:
                missing_non_blocking.extend([f"{req.section}.{f}" for f in missing])

    return {
        "package_complete": len(missing_blocking) == 0,
        "missing_blocking_fields": missing_blocking,
        "missing_advisory_fields": missing_non_blocking,
        "gate_can_proceed": len(missing_blocking) == 0,
    }

# Example usage
package = GateEvidencePackage(
    initiative_name="Claims Triage Agent",
    gate_name="feasibility",
    submitted_data={
        "model_performance": {
            "test_set_accuracy": 0.87,
            "target_accuracy": 0.90,
            "test_set_size": 2400,
            "test_set_description": "Random sample of H1 2024 claims across all categories"
        },
        "data_assessment": {
            "training_data_size": 15000,
            "data_quality_score": 0.91,
            # Missing: coverage_assessment
        },
        "business_case": {
            "projected_annual_benefit": 2400000,
            "implementation_cost": 350000,
            "payback_period_months": 2.1
        }
    }
)

result = validate_evidence_package(package, FEASIBILITY_GATE_REQUIREMENTS)
print(f"Package complete: {result['package_complete']}")
print(f"Gate can proceed: {result['gate_can_proceed']}")
if result["missing_blocking_fields"]:
    print(f"Missing blocking fields: {result['missing_blocking_fields']}")
